insert into public.formulas (slug, formula_json)
values (
  'cv-calculator',
  $json${"id": "cv-calculator", "name": "CV Calculator (Flow Coefficient)", "tag": "Flow Coefficient", "icon": "💧", "description": "Cv is defined as the flow of water at 60°F in gallons per minute at a pressure drop of 1 PSIG.", "formula": "Cv = Q<sub>L</sub> × √SG / √ΔP", "definitions": [{"symbol": "Q<sub>L</sub>", "label": "Flow Rate of Liquid"}, {"symbol": "SG", "label": "Specific Gravity"}, {"symbol": "ΔP", "label": "Differential Pressure"}], "unitSystems": {"SI": {"flow": "m3h", "pressure": "bar"}, "CGS": {"flow": "m3h", "pressure": "bar"}, "Imperial": {"flow": "gpm", "pressure": "psi"}}, "inputs": [{"id": "flow", "label": "Flow Rate", "default": 45, "units": [{"value": "gpm", "label": "GPM", "toBase": "v => v", "fromBase": "v => v"}, {"value": "m3h", "label": "m³/hr", "toBase": "v => v * 4.40286", "fromBase": "v => v / 4.40286"}, {"value": "lpm", "label": "L/min", "toBase": "v => v * 0.264172", "fromBase": "v => v / 0.264172"}]}, {"id": "sg", "label": "Specific Gravity", "default": 1, "units": [{"value": "sg", "label": "SG", "toBase": "v => v", "fromBase": "v => v"}]}, {"id": "pressure", "label": "Differential Pressure", "default": 0.8492, "units": [{"value": "psi", "label": "PSI", "toBase": "v => v", "fromBase": "v => v"}, {"value": "bar", "label": "BAR", "toBase": "v => v * 14.50377", "fromBase": "v => v / 14.50377"}, {"value": "kgcm2", "label": "Kg/cm²", "toBase": "v => v * 14.2233", "fromBase": "v => v / 14.2233"}, {"value": "kpa", "label": "kPa", "toBase": "v => v * 0.14504", "fromBase": "v => v / 0.14504"}]}], "calculate": {"steps": ["const q  = values.flow_unit.toBase(values.flow);", "const sg = values.sg;", "const dp = values.pressure_unit.toBase(values.pressure);", "if (q <= 0 || sg <= 0 || dp <= 0) return { results: [], derived: [] };", "const cv = q * Math.sqrt(sg) / Math.sqrt(dp);", "return { results: [{ label: 'Cv (Flow Coefficient)', value: cv.toFixed(4), unit: '—', highlight: true }], derived: [] };"]}}$json$::jsonb
)
on conflict (slug) do nothing;
insert into public.formulas (slug, formula_json)
values (
  'distance-conversion',
  $json${"id": "distance-conversion", "name": "Distance / Length Converter", "tag": "Unit Conversion", "icon": "📏", "description": "Converts a length / distance value between metric, CGS and imperial units — km, m, cm, mm, miles, yards, feet, inches.", "formula": "L<sub>target</sub> = L<sub>input</sub> × k", "definitions": [{"symbol": "L<sub>input</sub>", "label": "Input length value"}, {"symbol": "k", "label": "Conversion factor via base unit (metre)"}, {"symbol": "L<sub>target</sub>", "label": "Converted length in chosen output unit"}], "unitSystems": {"SI": {"value": "m"}, "CGS": {"value": "cm"}, "Imperial": {"value": "feet"}}, "inputs": [{"id": "value", "label": "Distance Value", "default": 1, "units": [{"value": "km", "label": "Kilometre (km)", "toBase": "v => v * 1000", "fromBase": "v => v / 1000"}, {"value": "m", "label": "Metre (m)", "toBase": "v => v", "fromBase": "v => v"}, {"value": "dm", "label": "Decimetre (dm)", "toBase": "v => v * 0.1", "fromBase": "v => v / 0.1"}, {"value": "cm", "label": "Centimetre (cm)", "toBase": "v => v * 0.01", "fromBase": "v => v / 0.01"}, {"value": "mm", "label": "Millimetre (mm)", "toBase": "v => v * 0.001", "fromBase": "v => v / 0.001"}, {"value": "um", "label": "Micrometre (µm)", "toBase": "v => v * 1e-6", "fromBase": "v => v / 1e-6"}, {"value": "mile", "label": "Mile (mi)", "toBase": "v => v * 1609.344", "fromBase": "v => v / 1609.344"}, {"value": "yard", "label": "Yard (yd)", "toBase": "v => v * 0.9144", "fromBase": "v => v / 0.9144"}, {"value": "feet", "label": "Foot (ft)", "toBase": "v => v * 0.3048", "fromBase": "v => v / 0.3048"}, {"value": "inch", "label": "Inch (in)", "toBase": "v => v * 0.0254", "fromBase": "v => v / 0.0254"}, {"value": "nm", "label": "Nautical Mile", "toBase": "v => v * 1852", "fromBase": "v => v / 1852"}]}, {"id": "target", "label": "Convert To", "default": 1, "dropdownOnly": true, "units": [{"value": "km", "label": "Kilometre (km)", "toBase": "v => v * 1000", "fromBase": "v => v / 1000"}, {"value": "m", "label": "Metre (m)", "toBase": "v => v", "fromBase": "v => v"}, {"value": "dm", "label": "Decimetre (dm)", "toBase": "v => v * 0.1", "fromBase": "v => v / 0.1"}, {"value": "cm", "label": "Centimetre (cm)", "toBase": "v => v * 0.01", "fromBase": "v => v / 0.01"}, {"value": "mm", "label": "Millimetre (mm)", "toBase": "v => v * 0.001", "fromBase": "v => v / 0.001"}, {"value": "um", "label": "Micrometre (µm)", "toBase": "v => v * 1e-6", "fromBase": "v => v / 1e-6"}, {"value": "mile", "label": "Mile (mi)", "toBase": "v => v * 1609.344", "fromBase": "v => v / 1609.344"}, {"value": "yard", "label": "Yard (yd)", "toBase": "v => v * 0.9144", "fromBase": "v => v / 0.9144"}, {"value": "feet", "label": "Foot (ft)", "toBase": "v => v * 0.3048", "fromBase": "v => v / 0.3048"}, {"value": "inch", "label": "Inch (in)", "toBase": "v => v * 0.0254", "fromBase": "v => v / 0.0254"}, {"value": "nm", "label": "Nautical Mile", "toBase": "v => v * 1852", "fromBase": "v => v / 1852"}]}], "calculate": {"steps": ["const meters    = values.value_unit.toBase(values.value);", "const converted = values.target_unit.fromBase(meters);", "function fmt(n) { if(Math.abs(n)>=1000) return n.toFixed(2); if(Math.abs(n)>=1) return parseFloat(n.toFixed(4)).toString(); return n.toPrecision(4); }", "return { results: [{ label: values.value + ' ' + values.value_unit.label + ' =', value: fmt(converted), unit: values.target_unit.label, highlight: true }], derived: [{ label: 'Kilometres', value: fmt(meters/1000), unit: 'km' }, { label: 'Metres', value: fmt(meters), unit: 'm' }, { label: 'Centimetres', value: fmt(meters/0.01), unit: 'cm' }, { label: 'Millimetres', value: fmt(meters/0.001), unit: 'mm' }, { label: 'Feet', value: fmt(meters/0.3048), unit: 'ft' }, { label: 'Inches', value: fmt(meters/0.0254), unit: 'in' }, { label: 'Miles', value: fmt(meters/1609.344), unit: 'mi' }] };"]}}$json$::jsonb
)
on conflict (slug) do nothing;
insert into public.formulas (slug, formula_json)
values (
  'sample-pressure-drop',
  $json${"id": "pressure-drop", "name": "Pressure Drop (Darcy-Weisbach)", "tag": "Fluid Mechanics", "icon": "🔧", "description": "Calculates pressure drop in a pipe using the Darcy-Weisbach equation.", "formula": "ΔP = f × (L/D) × (ρV²/2)", "definitions": [{"symbol": "f", "label": "Darcy friction factor (dimensionless)"}, {"symbol": "L", "label": "Pipe length"}, {"symbol": "D", "label": "Pipe internal diameter"}, {"symbol": "ρ", "label": "Fluid density"}, {"symbol": "V", "label": "Flow velocity"}, {"symbol": "ΔP", "label": "Pressure drop"}], "unitSystems": {"SI": {"length": "m", "diameter": "m", "density": "kgm3", "velocity": "ms"}, "CGS": {"length": "cm", "diameter": "cm", "density": "gcm3", "velocity": "cms"}, "Imperial": {"length": "ft", "diameter": "inch", "density": "lbft3", "velocity": "fts"}}, "inputs": [{"id": "friction", "label": "Friction Factor (f)", "default": 0.02, "units": [{"value": "dimless", "label": "—", "toBase": "v => v", "fromBase": "v => v"}]}, {"id": "length", "label": "Pipe Length (L)", "default": 100, "units": [{"value": "m", "label": "m", "toBase": "v => v", "fromBase": "v => v"}, {"value": "cm", "label": "cm", "toBase": "v => v*0.01", "fromBase": "v => v/0.01"}, {"value": "ft", "label": "ft", "toBase": "v => v*0.3048", "fromBase": "v => v/0.3048"}]}, {"id": "diameter", "label": "Pipe Diameter (D)", "default": 0.1, "units": [{"value": "m", "label": "m", "toBase": "v => v", "fromBase": "v => v"}, {"value": "cm", "label": "cm", "toBase": "v => v*0.01", "fromBase": "v => v/0.01"}, {"value": "mm", "label": "mm", "toBase": "v => v*0.001", "fromBase": "v => v/0.001"}, {"value": "inch", "label": "inch", "toBase": "v => v*0.0254", "fromBase": "v => v/0.0254"}, {"value": "ft", "label": "ft", "toBase": "v => v*0.3048", "fromBase": "v => v/0.3048"}]}, {"id": "density", "label": "Fluid Density (ρ)", "default": 1000, "units": [{"value": "kgm3", "label": "kg/m³", "toBase": "v => v", "fromBase": "v => v"}, {"value": "gcm3", "label": "g/cm³", "toBase": "v => v*1000", "fromBase": "v => v/1000"}, {"value": "lbft3", "label": "lb/ft³", "toBase": "v => v*16.0185", "fromBase": "v => v/16.0185"}]}, {"id": "velocity", "label": "Flow Velocity (V)", "default": 2, "units": [{"value": "ms", "label": "m/s", "toBase": "v => v", "fromBase": "v => v"}, {"value": "cms", "label": "cm/s", "toBase": "v => v*0.01", "fromBase": "v => v/0.01"}, {"value": "fts", "label": "ft/s", "toBase": "v => v*0.3048", "fromBase": "v => v/0.3048"}]}], "calculate": {"steps": ["const f   = values.friction;", "const L   = values.length_unit.toBase(values.length);", "const D   = values.diameter_unit.toBase(values.diameter);", "const rho = values.density_unit.toBase(values.density);", "const V   = values.velocity_unit.toBase(values.velocity);", "if(D<=0) return {results:[],derived:[]};", "const dP_pa  = f * (L/D) * (rho * V * V / 2);", "const dP_bar = dP_pa / 1e5;", "const dP_psi = dP_pa * 0.000145038;", "return { results: [ { label:'Pressure Drop', value: dP_pa.toFixed(2), unit:'Pa', highlight:true }, { label:'Pressure Drop', value: dP_bar.toFixed(4), unit:'bar' } ], derived: [ { label:'Velocity', value: V.toFixed(3), unit:'m/s' }, { label:'L/D Ratio', value: (L/D).toFixed(2), unit:'-' }, { label:'Dynamic Pressure', value: (rho*V*V/2).toFixed(2), unit:'Pa' }, { label:'in PSI', value: dP_psi.toFixed(4), unit:'psi' } ] };"]}}$json$::jsonb
)
on conflict (slug) do nothing;
insert into public.formulas (slug, formula_json)
values (
  'waterjet-force',
  $json${"id": "waterjet-force", "name": "Waterjet Force / Thrust Calculator", "tag": "Thrust", "icon": "🚀", "description": "Calculates the thrust (reaction force) produced by a waterjet nozzle using the momentum equation: WJF = V × MFR.", "formula": "WJF = V × MFR", "definitions": [{"symbol": "V", "label": "Velocity of fluid (m/s)"}, {"symbol": "MFR", "label": "Mass Flow Rate (kg/s)"}, {"symbol": "WJF", "label": "Water Jet Force / Thrust (N or kg)"}], "unitSystems": {"SI": {"density": "kgm3", "diameter": "mm", "flow": "m3h"}, "CGS": {"density": "gcm3", "diameter": "cm", "flow": "m3h"}, "Imperial": {"density": "lbft3", "diameter": "inch", "flow": "gpm"}}, "inputs": [{"id": "density", "label": "Specific Density of Fluid", "default": 1000, "units": [{"value": "kgm3", "label": "kg/m³", "toBase": "v => v", "fromBase": "v => v"}, {"value": "gcm3", "label": "g/cm³", "toBase": "v => v * 1000", "fromBase": "v => v / 1000"}, {"value": "lbft3", "label": "lb/ft³", "toBase": "v => v * 16.0185", "fromBase": "v => v / 16.0185"}]}, {"id": "diameter", "label": "Pipe / Nozzle Diameter", "default": 450, "units": [{"value": "mm", "label": "mm", "toBase": "v => v / 1000", "fromBase": "v => v * 1000"}, {"value": "cm", "label": "cm", "toBase": "v => v / 100", "fromBase": "v => v * 100"}, {"value": "m", "label": "m", "toBase": "v => v", "fromBase": "v => v"}, {"value": "inch", "label": "inch", "toBase": "v => v * 0.0254", "fromBase": "v => v / 0.0254"}]}, {"id": "flow", "label": "Flow Rate", "default": 2400, "units": [{"value": "m3h", "label": "m³/hr", "toBase": "v => v / 3600", "fromBase": "v => v * 3600"}, {"value": "m3s", "label": "m³/s", "toBase": "v => v", "fromBase": "v => v"}, {"value": "lpm", "label": "L/min", "toBase": "v => v / 60000", "fromBase": "v => v * 60000"}, {"value": "gpm", "label": "GPM", "toBase": "v => v * 6.309e-5", "fromBase": "v => v / 6.309e-5"}]}], "calculate": {"steps": ["const rho   = values.density_unit.toBase(values.density);", "const dia_m = values.diameter_unit.toBase(values.diameter);", "const q_m3s = values.flow_unit.toBase(values.flow);", "if (rho <= 0 || dia_m <= 0 || q_m3s <= 0) return { results: [], derived: [] };", "const area   = Math.PI * (dia_m / 2) ** 2;", "const vel    = q_m3s / area;", "const mfr    = rho * q_m3s;", "const wjf_n  = vel * mfr;", "const wjf_kg = wjf_n / 9.80665;", "return { results: [{ label: 'WJF / Thrust', value: wjf_kg.toFixed(2), unit: 'kg' }, { label: 'WJF / Thrust', value: wjf_n.toFixed(2), unit: 'N', highlight: true }], derived: [{ label: 'X-Section Area', value: area.toFixed(4), unit: 'm²' }, { label: 'Flow Rate', value: q_m3s.toFixed(4), unit: 'm³/s' }, { label: 'Velocity (V)', value: vel.toFixed(4), unit: 'm/s' }, { label: 'Mass Flow Rate', value: mfr.toFixed(2), unit: 'kg/s' }] };"]}}$json$::jsonb
)
on conflict (slug) do nothing;